-- Email Templates table
-- Run this in your Supabase SQL Editor

create table if not exists email_templates (
  id uuid default uuid_generate_v4() primary key,
  name varchar(255) not null,
  slug varchar(255) unique not null,
  description text,
  category varchar(100) not null default 'transactional',
  subject_template text,
  html_body text not null,
  trigger_event varchar(100),
  is_active boolean default true not null,
  variables jsonb default '[]'::jsonb,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  updated_at timestamp with time zone default timezone('utc'::text, now()) not null
);

create index if not exists idx_email_templates_slug on email_templates(slug);
create index if not exists idx_email_templates_category on email_templates(category);
create index if not exists idx_email_templates_trigger on email_templates(trigger_event);

-- Seed: All existing email templates from src/lib/email.ts

insert into email_templates (name, slug, description, category, subject_template, html_body, trigger_event, variables) values

-- Auth emails
('Email Verification', 'email-verification', '6-digit OTP code for email verification', 'transactional',
