 '<div style="font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif;background:#06060b;padding:40px 20px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td align="center"><table width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;background:#13131d;border:1px solid rgba(255,255,255,0.06);border-radius:16px;overflow:hidden;"><tr><td style="padding:32px 32px 24px;text-align:center;"><div style="width:48px;height:48px;border-radius:12px;background:linear-gradient(135deg,#f59e0b,#ef4444);margin:0 auto 16px;line-height:48px;text-align:center;"><span style="color:white;font-size:20px;">&#9888;</span></div><h1 style="margin:0;font-size:22px;font-weight:700;color:#f1f5f9;">Your trial expires in {{days_left}} days</h1><p style="margin:6px 0 0;font-size:14px;color:#94a3b8;">Keep your store live</p></td></tr><tr><td style="padding:0 32px 24px;"><p style="margin:0;font-size:15px;color:#e0e0e0;line-height:1.6;">Hi {{name}},</p><p style="margin:12px 0 0;font-size:15px;color:#e0e0e0;line-height:1.6;">Your free trial for <strong>{{store_name}}</strong> expires in {{days_left}} day{{days_left}}. Upgrade now to keep your store live and continue receiving orders.</p></td></tr><tr><td style="padding:8px 32px 32px;text-align:center;"><a href="{{app_url}}/upgrade" style="display:inline-block;padding:14px 36px;background:linear-gradient(135deg,#a855f7,#7c3aed);color:#fff;font-size:14px;font-weight:600;border-radius:10px;text-decoration:none;">Upgrade Now</a></td></tr></table></td></tr></table></div>',
 'marketing.trial_nurture_day5', '["name","store_name","store_slug","days_left"]'::jsonb),

('Upgrade Thank You', 'upgrade-thank-you', 'Post-upgrade confirmation', 'marketing',
 'Welcome to {{plan}} — {{store_name}} is now premium',
 '<div style="font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif;background:#06060b;padding:40px 20px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td align="center"><table width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;background:#13131d;border:1px solid rgba(255,255,255,0.06);border-radius:16px;overflow:hidden;"><tr><td style="padding:32px 32px 24px;text-align:center;"><div style="width:48px;height:48px;border-radius:12px;background:linear-gradient(135deg,#10b981,#06b6d4);margin:0 auto 16px;line-height:48px;text-align:center;"><span style="color:white;font-size:20px;">&#127881;</span></div><h1 style="margin:0;font-size:22px;font-weight:700;color:#f1f5f9;">Welcome to {{plan}}!</h1><p style="margin:6px 0 0;font-size:14px;color:#94a3b8;">Thank you for upgrading</p></td></tr><tr><td style="padding:0 32px 24px;"><p style="margin:0;font-size:15px;color:#e0e0e0;line-height:1.6;">Hi {{name}},</p><p style="margin:12px 0 0;font-size:15px;color:#e0e0e0;line-height:1.6;">You''ve upgraded <strong>{{store_name}}</strong> to the <strong>{{plan}}</strong> plan. Your store now has all premium features unlocked.</p></td></tr><tr><td style="padding:8px 32px 32px;text-align:center;"><a href="{{app_url}}/dashboard" style="display:inline-block;padding:12px 32px;background:linear-gradient(135deg,#a855f7,#7c3aed);color:#fff;font-size:14px;font-weight:600;border-radius:10px;text-decoration:none;">Go to Dashboard</a></td></tr></table></td></tr></table></div>',
 'marketing.upgrade', '["name","store_name","plan"]'::jsonb),

('Win-Back Email', 'win-back-email', 'Re-engagement for expired subscriptions', 'marketing',
 'We miss you — bring {{store_name}} back online',
 '<div style="font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif;background:#06060b;padding:40px 20px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td align="center"><table width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;background:#13131d;border:1px solid rgba(255,255,255,0.06);border-radius:16px;overflow:hidden;"><tr><td style="padding:32px 32px 24px;text-align:center;"><div style="width:48px;height:48px;border-radius:12px;background:linear-gradient(135deg,#a855f7,#06b6d4);margin:0 auto 16px;line-height:48px;text-align:center;"><span style="color:white;font-size:20px;">&#128148;</span></div><h1 style="margin:0;font-size:22px;font-weight:700;color:#f1f5f9;">We miss you!</h1><p style="margin:6px 0 0;font-size:14px;color:#94a3b8;">{{store_name}} is offline</p></td></tr><tr><td style="padding:0 32px 24px;"><p style="margin:0;font-size:15px;color:#e0e0e0;line-height:1.6;">Hi {{name}},</p><p style="margin:12px 0 0;font-size:15px;color:#e0e0e0;line-height:1.6;">It''s been {{days_since_expiry}} days since your subscription expired. Your store <strong>{{store_name}}</strong> is currently offline and customers can''t browse your products.</p></td></tr><tr><td style="padding:8px 32px 32px;text-align:center;"><a href="{{app_url}}/upgrade" style="display:inline-block;padding:14px 36px;background:linear-gradient(135deg,#a855f7,#7c3aed);color:#fff;font-size:14px;font-weight:600;border-radius:10px;text-decoration:none;">Reactivate Your Store</a></td></tr></table></td></tr></table></div>',
 'marketing.win_back', '["name","store_name","store_slug","days_since_expiry"]'::jsonb),

