 'Weekly report for {{store_name}} — {{visits}} visits, {{orders}} orders',
 '<div style="font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif;background:#06060b;padding:40px 20px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td align="center"><table width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;background:#13131d;border:1px solid rgba(255,255,255,0.06);border-radius:16px;overflow:hidden;"><tr><td style="padding:32px 32px 24px;text-align:center;"><div style="width:48px;height:48px;border-radius:12px;background:linear-gradient(135deg,#a855f7,#06b6d4);margin:0 auto 16px;line-height:48px;text-align:center;"><span style="color:white;font-size:20px;">&#128200;</span></div><h1 style="margin:0;font-size:22px;font-weight:700;color:#f1f5f9;">Your Weekly Report</h1><p style="margin:6px 0 0;font-size:14px;color:#94a3b8;">{{store_name}}</p></td></tr><tr><td style="padding:0 32px 24px;"><p style="margin:0;font-size:15px;color:#e0e0e0;line-height:1.6;">Hi {{name}},</p><p style="margin:12px 0 0;font-size:15px;color:#e0e0e0;line-height:1.6;">Here''s your weekly performance summary.</p></td></tr><tr><td style="padding:8px 32px 32px;text-align:center;"><a href="{{app_url}}/dashboard" style="display:inline-block;padding:12px 32px;background:linear-gradient(135deg,#a855f7,#7c3aed);color:#fff;font-size:14px;font-weight:600;border-radius:10px;text-decoration:none;">View Full Dashboard</a></td></tr></table></td></tr></table></div>',
 'marketing.weekly_digest', '["name","store_name","store_slug","visits","orders","whatsapp_clicks","top_product"]'::jsonb)

